using Microsoft.AspNetCore.Mvc;
using System.IO;
using System.Net.Mime;

[Route("api/files")]
[ApiController]
public class FilesController : ControllerBase
{
    private readonly string _uploadsFolder = Path.Combine(Directory.GetCurrentDirectory(), "uploads");

    [HttpGet("{filename}")]
    public IActionResult GetFile(string filename)
    {
        var filePath = Path.Combine(_uploadsFolder, filename);

        if (!System.IO.File.Exists(filePath) || !filePath.StartsWith(_uploadsFolder))
        {
            return NotFound();
        }

        var fileExtension = Path.GetExtension(filePath).ToLowerInvariant();
        var contentType = fileExtension switch
        {
            ".jpg" or ".jpeg" => MediaTypeNames.Image.Jpeg,
            ".png" => MediaTypeNames.Image.Png,
            ".gif" => MediaTypeNames.Image.Gif,
            ".pdf" => MediaTypeNames.Application.Pdf,
            ".txt" => MediaTypeNames.Text.Plain,
            ".doc" or ".docx" => MediaTypeNames.Application.Octet,
            ".xls" or ".xlsx" => MediaTypeNames.Application.Octet,
            _ => MediaTypeNames.Application.Octet,
        };

        var fileBytes = System.IO.File.ReadAllBytes(filePath);
        return File(fileBytes, contentType, Path.GetFileName(filePath));
    }
}